// StudentClass definition
class Student {
    String name;
    int age;

    // When argument and field names are the same, use this to distinguish
    // setInfoMethod definition
    void setInfo(String name, int age) {
        this.name = name; // this.name = Fields、name = Arguments
        this.age = age;
    }

    // Problem when not using this
    // badSetNameMethod definition
    void badSetName(String name) {
        name = name; // Just assigning argument to itself!
        // Fields don't change
    }

    // this can also return itself
    Student withName(String name) {
        this.name = name;
        return this; // Method chain can be used for
    }

    void display() {
        System.out.println(name + "(" + age + " years old)");
    }
}

Student s = new Student();
s.setInfo("Taro", 20);
s.display(); // Taro(20 years old)

// Method chain
new Student().withName("Hanako").display(); // Hanako(0 years old)

