class Product {
    String name;
    int price;
    String category;

    // Full constructor
    Product(String name, int price, String category) {
        this.name = name;
        this.price = price;
        this.category = category;
    }

    // 2Arguments version: Using this() to call 3Arguments version
    Product(String name, int price) {
        this(name, price, "General"); // Call another constructor on the first line
    }

    // 1Arguments version: Using this() to call 2Arguments version
    Product(String name) {
        this(name, 0); // Chain: → 2Arguments → 3Arguments
    }

    void show() {
        System.out.println(name + " ¥" + price + " [" + category + "]");
    }
}

new Product("Intro to Java", 2980, "Book").show();
// Intro to Java ¥2980 [Book]

new Product("Notebook", 200).show();
// Notebook ¥200 [General]

new Product("Sample").show();
// Sample ¥0 [General]

