// BankAccountClass definition
class BankAccount {
    private String owner;
    private int balance;

    public BankAccount(String owner, int initialBalance) {
        this.owner = owner;
        this.balance = Math.max(0, initialBalance);
    }

    // getter(Read-only access)
    // getOwnerMethod definition
    public String getOwner() {
        return owner;
    }

    // getBalanceMethod definition
    public int getBalance() {
        return balance;
    }

    // setter(Write with validation)
    public void deposit(int amount) {
        // Conditional branching
        if (amount <= 0) {
            System.out.println("Invalid amount");
            return;
        }
        balance += amount;
    }

    public boolean withdraw(int amount) {
        if (amount <= 0 || amount > balance) {
            System.out.println("Cannot withdraw");
            return false;
        }
        balance -= amount;
        return true;
    }
}
BankAccount acc = new BankAccount("Taro", 1000);
// acc.balance = -999; // Compilation error! private
acc.deposit(500);
System.out.println(acc.getBalance()); // 1500
acc.withdraw(2000); // Cannot withdraw

