class Employee {
    // staticFields(ClassVariable): Shared among all instances
    static int totalCount = 0;
    static String company = "Tech Corp.";

    // InstanceFields: Independent for each object
    String name;
    int id;

    Employee(String name) {
        this.name = name;
        totalCount++;  // Instance creation  increments count
        this.id = totalCount;
    }

    // staticMethod: Can be called without an object
    // getTotalMethod definition
    static int getTotal() {
        // this.name; // Compilation error!Cannot access instance members from static
        return totalCount;
    }

    // Instance method: Can also access static members
    // showMethod definition
    void show() {
        System.out.println(company + " " + name + " (ID:" + id + ")");
    }
}

