// PointClass definition
class Point {
    int x, y;

    Point(int x, int y) {
        this.x = x;
        this.y = y;
    }
    @Override
    // equalsMethod definition
    public boolean equals(Object obj) {
        // 1. Same object check
        // Conditional branching
        if (this == obj) return true;
        // 2. null & TypeCheck
        if (!(obj instanceof Point)) return false;
        // 3. FieldsComparison
        Point other = (Point) obj;
        return this.x == other.x && this.y == other.y;
    }
    @Override
    // hashCodeMethod definition
    public int hashCode() {
        // If equals is true, must return the same hashCode
        return 31 * x + y;
    }
    @Override
    public String toString() {
        return "(" + x + ", " + y + ")";
    }
}
Point p1 = new Point(3, 4);
Point p2 = new Point(3, 4);
Point p3 = new Point(1, 2);

System.out.println(p1 == p2);      // false(References differ)
System.out.println(p1.equals(p2)); // true(Values are equal)
System.out.println(p1.equals(p3)); // false

