// Package naming conventions:
// Reversed domain name format is conventional
// com.example.app
// jp.co.company.project

// java.lang Classes in package don't need import
// String, Integer, System, Math etc.

// Fully qualified name(No import needed but code gets longer)
java.util.ArrayList<String> list = new java.util.ArrayList<>();

// 1. finalVariable: Reassignment not allowed
final int MAX = 100;
// MAX = 200; // Compilation error!

// finalReferenceType: Reference reassignment not allowed, content modification is OK
final List<String> list = new ArrayList<>();
list.add("OK");          // OK! Content modification is allowed
// list = new ArrayList<>(); // Compilation error! Reference reassignment not allowed

// 2. finalMethod: Cannot override
class Parent {
    final void important() {
        System.out.println("Method that cannot be changed");
    }
}
class Child extends Parent {
